import sys

class Solution:
    def subarraysWithKDistinct(self, arr: list[int], k: int) -> int:
        def at_most(k):
            left = 0
            count = {}
            res = 0
            for right in range(len(arr)):
                count[arr[right]] = count.get(arr[right], 0) + 1
                while len(count) > k:
                    count[arr[left]] -= 1
                    if count[arr[left]] == 0:
                        del count[arr[left]]
                    left += 1
                res += len(arr) - right
            return res
        return at_most(k) - at_most(k - 1)

