#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int subarraysWithKDistinct(vector<int>& arr, int k) {
        return atMost(arr, k) - atMost(arr, k - 1);
    }
private:
    int atMost(vector<int>& arr, int k) {
        int left = 0;
        unordered_map<int, int> count;
        int res = 0;
        for (int right = 0; right < arr.size(); right++) {
            count[arr[right]]++;
            while (count.size() > k) {
                count[arr[left]]--;
                if (count[arr[left]] == 0) {
                    count.erase(arr[left]);
                }
                left++;
            }
            res += arr.size() - right;
        }
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> arr(n);
    for (int i = 0; i < n; i++) cin >> arr[i];
    int k;
    if (!(cin >> k)) return 0;
    Solution sol;
    int ans = sol.subarraysWithKDistinct(arr, k);
    cout << ans << "\n";
    return 0;
}
